/**
 * @summary Get shoutbox messages
 */
export const getGetShoutboxUrl = (params?: GetShoutboxParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/shoutbox?${stringifiedParams}`
    : `/api/shoutbox`;
};

export const getShoutbox = async (
  params?: GetShoutboxParams,
  options?: RequestInit,
): Promise<ShoutboxMessage[]> => {
  return customFetch<ShoutboxMessage[]>(getGetShoutboxUrl(params), {
    ...options,
    method: "GET",
  });
};

